const e=JSON.parse(`{"key":"v-4f9e78cb","path":"/project/%E7%BB%84%E4%BB%B6%E5%BA%93%E4%B9%8B%E7%BB%84%E4%BB%B6%E5%AE%9E%E4%BE%8B.html","title":"组件库之项目实例：使用插件封装多选虚拟长列表","lang":"zh-CN","frontmatter":{"title":"组件库之项目实例：使用插件封装多选虚拟长列表","isTimeLine":true,"date":"2026-01-08T00:00:00.000Z","category":["前端"],"tag":["JavaScript","Vue"]},"headers":[{"level":3,"title":"场景","slug":"场景","link":"#场景","children":[]},{"level":3,"title":"解决方案","slug":"解决方案","link":"#解决方案","children":[]},{"level":3,"title":"实现","slug":"实现","link":"#实现","children":[]}],"git":{"createdTime":1773458982000,"updatedTime":1773506313000,"contributors":[{"name":"liunal","email":"liunal","commits":2}]},"readingTime":{"minutes":1.73,"words":520},"filePathRelative":"project/组件库之组件实例.md","localizedDate":"2026年1月8日","excerpt":"<h3> 场景</h3>\\n<ol>\\n<li>系统一些场景的多选选择器，内容过长过多一般有上千条数据，并且选择多个后也不好显示以及删除单个，所以需要一个多选列表组件。</li>\\n<li>它有搜索框、可以单选与多选，单选是上下布局，多选显示左右布局。</li>\\n</ol>\\n<h3> 解决方案</h3>\\n<ol>\\n<li>使用插件<code>vue-virtual-scroller</code>,它是长列表优化方案之一。</li>\\n<li>原理是：它只会把展示给用户的那部分 dom 渲染出来，比如滚到上面的 dom 就会回收掉</li>\\n</ol>\\n<h3> 实现</h3>\\n<ol>\\n<li>根据传进来的参数<code>multiple（true\\\\false）</code>决定页面的布局，如果单选则显示为上下布局；多选则为左右布局，右边显示选中的值。\\n<ul>\\n<li>页面的布局根据<code>flex</code>的<code>flex-direction</code>显示。\\n<ul>\\n<li><code>style=\\"display:flex;overflow: auto;\\" :style=\\"{'flex-direction':mydirection}\\"</code></li>\\n</ul>\\n</li>\\n</ul>\\n</li>\\n<li>数据列表使用插件<code>vue-virtual-scroller</code>的<code>RecycleScroller组件</code>展示\\n<ul>\\n<li><code>RecycleScroller</code>组件是做固定高度场景，需指定<code>items itemsize keyfield</code>, keyfieled需唯一稳定\\n<ul>\\n<li>代码：<code>&lt;RecycleScroller style=\\"height: 100%;\\" :items=\\"renderList\\" :item-size=\\"32\\" key-field=\\"name\\" v-slot=\\"{ item }\\"&gt;</code></li>\\n</ul>\\n</li>\\n<li>多选模式：主要是每个item都有_checked选项，点击设置<code>item._checked = !item._checked；</code></li>\\n<li>搜索关键字：为了用户体验过滤后的列表数据项中的关键字为黄色。\\n<ul>\\n<li>每个数据项会循环匹配是否有keyword，根据replace方法把值替换上带strong标签与样式的关键值。<code>item.text.replace(new RegExp(_firstword, \\"gm\\"), &lt;strong class=\\"searchText\\"&gt;\${_firstword}&lt;/strong&gt;)</code></li>\\n</ul>\\n</li>\\n</ul>\\n</li>\\n<li>列表自定义选项渲染：比如左边数据列表需要禁选效果，点击可以提示原因,使用作用域插槽实现\\n<ul>\\n<li>列表自定义选项渲染，item值使用插槽占位，方便业务组件传递数据项内容，比如数据列表需要禁选效果，并且点击可以提示原因。</li>\\n</ul>\\n</li>\\n<li>业务系统使用组件：<code>&lt;fx-listselect style=\\"height: 100%;flex: 1;\\" layout=\\"row\\" :listdata=\\"options\\" v-model=\\"lstCheck\\"&gt;&lt;/fx-listselect&gt;</code></li>\\n</ol>"}`);export{e as data};
